// ===== EDIT YOUR SETTINGS HERE =====
// Defaults below match the Gumroad + n8n Creator listings.
// Change only what you need; leave unused destinations as placeholders.

// Where to log receipts:
//   'sheets'   -> Google Sheets only
//   'airtable' -> Airtable only
//   'both'     -> Google Sheets and Airtable
const EXPENSE_LOG = 'sheets';

const GOOGLE_SHEET_ID = 'your-google-sheet-id';
const SHEETS_TAB_NAME = 'Expenses';

const AIRTABLE_BASE_ID = 'appXXXXXXXXXXXXXX';
const EXPENSES_TABLE_NAME = 'Expenses';

// Where to send alerts for high-value, warranty, or review-needed receipts:
//   'slack' -> Slack only
//   'teams' -> Microsoft Teams only
//   'both'  -> Slack and Teams
//   'none'  -> no chat alerts
const NOTIFY_CHANNELS = 'slack';
const SLACK_CHANNEL = '#receipts';
const TEAMS_WEBHOOK_URL = 'https://outlook.office.com/webhook/your-teams-incoming-webhook';

const HIGH_VALUE_THRESHOLD = 250;
const DUPLICATE_WINDOW_DAYS = 45;
const WARRANTY_ALERT_ENABLED = true;
const ATTACHMENT_OCR_ENABLED = true;
const OCR_MIN_TEXT_CHARS = 80;
const DEFAULT_SOURCE = 'gmail_receipt';

const payload = $input.first().json;
const expenseLog = String(EXPENSE_LOG || 'sheets').toLowerCase().trim();
const notifyChannels = String(NOTIFY_CHANNELS || 'slack').toLowerCase().trim();

return [
  {
    json: {
      expenseLog,
      useSheetsLog: expenseLog === 'sheets' || expenseLog === 'both',
      useAirtableLog: expenseLog === 'airtable' || expenseLog === 'both',
      googleSheetId: GOOGLE_SHEET_ID,
      sheetsTabName: SHEETS_TAB_NAME,
      airtableBaseId: AIRTABLE_BASE_ID,
      expensesTableName: EXPENSES_TABLE_NAME,
      notifyChannels,
      useSlack: notifyChannels === 'slack' || notifyChannels === 'both',
      useTeams: notifyChannels === 'teams' || notifyChannels === 'both',
      slackChannel: SLACK_CHANNEL,
      teamsWebhookUrl: TEAMS_WEBHOOK_URL,
      highValueThreshold: HIGH_VALUE_THRESHOLD,
      duplicateWindowDays: DUPLICATE_WINDOW_DAYS,
      warrantyAlertEnabled: WARRANTY_ALERT_ENABLED,
      attachmentOcrEnabled: ATTACHMENT_OCR_ENABLED,
      ocrMinTextChars: OCR_MIN_TEXT_CHARS,
      defaultSource: DEFAULT_SOURCE,
      payload,
    },
  },
];

const inputItem = $input.first();
const settings = inputItem.json;
const binary = inputItem.binary || {};
const raw = settings.payload || {};

const htmlToText = (value) => String(value || '')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>/gi, '\n')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+\n/g, '\n')
  .replace(/[ \t]+/g, ' ')
  .trim();

const headers = raw.headers || raw.payload?.headers || {};
const subject = raw.subject || raw.Subject || headers.subject || raw.payload?.subject || '';
const fromEmail = raw.from || raw.From || headers.from || raw.payload?.from || '';
const messageId = raw.id || raw.messageId || raw.message_id || raw.payload?.id || `receipt-${Date.now()}`;
const receivedAt = raw.date || raw.internalDate || raw.receivedAt || new Date().toISOString();
const textBody = raw.textPlain || raw.text || raw.snippet || raw.body?.text || '';
const htmlBody = raw.textHtml || raw.html || raw.body?.html || '';
const rawText = htmlToText(textBody || htmlBody || raw.snippet || JSON.stringify(raw).slice(0, 6000));

const compact = rawText.toLowerCase().replace(/\s+/g, ' ').slice(0, 1000);
const receiptHash = `${fromEmail}|${subject}|${compact}`.toLowerCase();
const attachmentBinaryProperties = Object.keys(binary).filter((name) => name.startsWith('attachment_'));
const imageAttachmentProperties = attachmentBinaryProperties.filter((name) =>
  String(binary[name]?.mimeType || '').toLowerCase().startsWith('image/')
);
const pdfAttachmentProperties = attachmentBinaryProperties.filter((name) =>
  String(binary[name]?.mimeType || '').toLowerCase().includes('pdf')
);
const ocrBinaryProperty = imageAttachmentProperties[0] || '';
const needsOcrFallback = Boolean(
  settings.attachmentOcrEnabled &&
    rawText.length < (settings.ocrMinTextChars ?? 80) &&
    ocrBinaryProperty
);

return [
  {
    json: {
      ...settings,
      messageId: String(messageId),
      receivedAt,
      source: raw.source || settings.defaultSource || 'gmail_receipt',
      originalSubject: String(subject),
      fromEmail: String(fromEmail),
      rawText: rawText.slice(0, 10000),
      rawTextSnippet: rawText.slice(0, 1000),
      receiptHash,
      attachmentBinaryProperties,
      imageAttachmentProperties,
      pdfAttachmentProperties,
      ocrBinaryProperty,
      needsOcrFallback,
      _mockExistingReceipts: Array.isArray(raw._mockExistingReceipts) ? raw._mockExistingReceipts : [],
      _testScenario: raw._testScenario || raw.scenario || '',
    },
    binary,
  },
];

const source = $('Normalize Email Structure').first();
const receipt = source.json;
const rows = $input
  .all()
  .map((item) => item.json)
  .filter((row) => !row._mockEmpty)
  .map((row) => row.fields || row);
return [{ json: { ...receipt, _lookupRows: rows }, binary: source.binary || {} }];

const source = $('Normalize Email Structure').first();
const receipt = source.json;
return [{ json: { ...receipt, _lookupRows: [] }, binary: source.binary || {} }];

function fromNode(name) {
  try {
    return $(name).first().json;
  } catch (error) {
    return null;
  }
}

const prev =
  fromNode('Compile Airtable Data') ||
  fromNode('Bypass Airtable Data Collection') ||
  $('Normalize Email Structure').first().json;
const source = $('Normalize Email Structure').first();

const sheetRows = $input
  .all()
  .map((item) => item.json)
  .filter((row) => !row._mockEmpty)
  .map((row) => row.fields || row);

return [{ json: { ...prev, _lookupRows: [...(prev._lookupRows || []), ...sheetRows] }, binary: source.binary || {} }];

const inputItem = $input.first();
const receipt = inputItem.json;
const rows = Array.isArray(receipt._lookupRows) ? receipt._lookupRows : [];
const windowDays = receipt.duplicateWindowDays ?? 45;
const cutoff = Date.now() - windowDays * 24 * 60 * 60 * 1000;

const isDuplicate = rows.some((row) => {
  const record = row.fields || row;
  if (record._mockEmpty) return false;
  const existingMessageId = String(record['Message ID'] || record.messageId || '').trim();
  const existingHash = String(record['Receipt Hash'] || record.receiptHash || '').toLowerCase();
  const existingAt = Date.parse(record['Received At'] || record.receivedAt || record.createdTime || '');

  if (receipt.messageId && existingMessageId && receipt.messageId === existingMessageId) {
    if (!existingAt || existingAt >= cutoff) return true;
  }

  if (receipt.receiptHash && existingHash && receipt.receiptHash === existingHash) {
    if (!existingAt || existingAt >= cutoff) return true;
  }

  return false;
});

return [{ json: { ...receipt, isDuplicate }, binary: inputItem.binary || {} }];

