const receiptItem = $('Check Receipt Duplication').first();
const receipt = receiptItem.json;
const aiItem = $input.first().json;
const raw =
  aiItem.message?.content ||
  aiItem.content ||
  aiItem.text ||
  aiItem.output ||
  aiItem.output_text ||
  aiItem.choices?.[0]?.message?.content ||
  '';

let extraction = {
  isReceipt: true,
  extractionStatus: 'extracted',
  failureReason: '',
  merchant: 'Unknown merchant',
  purchaseDate: '',
  total: 0,
  currency: 'USD',
  category: 'Uncategorized',
  taxDeductible: false,
  taxCategory: '',
  paymentMethod: '',
  lastFour: '',
  items: [],
  warrantyItems: [],
  returnDeadline: '',
  warrantyEndDate: '',
  aiSummary: '',
  confidence: 50,
  needsReview: true,
  notes: '',
};

let parsedOk = false;
try {
  const jsonMatch = String(raw).match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    extraction = { ...extraction, ...JSON.parse(jsonMatch[0]) };
    parsedOk = true;
  }
} catch (error) {
  extraction.aiSummary = String(raw).slice(0, 500);
  extraction.extractionStatus = 'failed';
  extraction.isReceipt = false;
  extraction.failureReason = 'OpenAI returned text that was not valid receipt JSON';
}

if (!parsedOk && !extraction.failureReason) {
  extraction.extractionStatus = 'failed';
  extraction.failureReason = 'OpenAI did not return a JSON object';
}

const toList = (value) => {
  if (Array.isArray(value)) return value.map((item) => String(item).trim()).filter(Boolean);
  return String(value || '')
    .split(/\n|, /)
    .map((item) => item.trim())
    .filter(Boolean);
};

const total = Number(String(extraction.total || 0).replace(/[^0-9.-]/g, '')) || 0;
const confidence = Math.max(0, Math.min(100, Number(extraction.confidence) || 50));
const items = toList(extraction.items);
const warrantyItems = toList(extraction.warrantyItems);
const highValue = total >= (receipt.highValueThreshold ?? 250);
const warrantyRelevant = Boolean(
  receipt.warrantyAlertEnabled &&
    (warrantyItems.length || extraction.returnDeadline || extraction.warrantyEndDate)
);
const needsReview = Boolean(
  extraction.needsReview || confidence < 70 || total <= 0 || !extraction.merchant || extraction.merchant === 'Unknown merchant'
);
const isReceipt = extraction.isReceipt !== false && extraction.extractionStatus !== 'not_receipt';
const severeMissingFields = Boolean(total <= 0 && (!extraction.merchant || extraction.merchant === 'Unknown merchant'));
const pdfOnlyNeedsExtraction = Boolean(
  (receipt.pdfAttachmentProperties || []).length &&
    !receipt.needsOcrFallback &&
    String(receipt.rawText || '').length < (receipt.ocrMinTextChars ?? 80)
);
const extractionFailed = Boolean(
  aiItem.error ||
    extraction.extractionStatus === 'failed' ||
    !parsedOk ||
    (pdfOnlyNeedsExtraction && severeMissingFields)
);
const extractionSucceeded = Boolean(isReceipt && !extractionFailed);

let route = 'standard';
if (!isReceipt) route = 'not_receipt';
else if (extractionFailed) route = 'extraction_failed';
else if (needsReview) route = 'review';
else if (highValue) route = 'high_value';
else if (warrantyRelevant) route = 'warranty';

const shouldAlert = receipt.notifyChannels !== 'none' && route !== 'standard' && extractionSucceeded;

return [
  {
    json: {
      ...receipt,
      merchant: String(extraction.merchant || 'Unknown merchant'),
      purchaseDate: String(extraction.purchaseDate || ''),
      total,
      currency: String(extraction.currency || 'USD'),
      category: String(extraction.category || 'Uncategorized'),
      taxDeductible: Boolean(extraction.taxDeductible),
      taxCategory: String(extraction.taxCategory || ''),
      paymentMethod: String(extraction.paymentMethod || ''),
      lastFour: String(extraction.lastFour || ''),
      items: items.join(' | '),
      warrantyItems: warrantyItems.join(' | '),
      returnDeadline: String(extraction.returnDeadline || ''),
      warrantyEndDate: String(extraction.warrantyEndDate || ''),
      aiSummary: String(extraction.aiSummary || `${extraction.merchant || 'Receipt'} - ${total}`),
      extractionSource: receipt.needsOcrFallback ? `attachment_ocr:${receipt.ocrBinaryProperty}` : 'email_text',
      isReceipt,
      extractionStatus: extractionFailed ? 'failed' : isReceipt ? 'extracted' : 'not_receipt',
      extractionSucceeded,
      extractionFailureReason:
        aiItem.error?.message ||
        extraction.failureReason ||
        (pdfOnlyNeedsExtraction && severeMissingFields
          ? 'PDF-only receipt attachment could not be extracted from the email body'
          : '') ||
        (!isReceipt ? 'Email or attachment does not appear to be a receipt' : ''),
      confidence,
      needsReview,
      highValue,
      warrantyRelevant,
      shouldAlert,
      route,
      notes: String(extraction.notes || ''),
    },
    binary: receiptItem.binary || {},
  },
];

const item = $input.first().json;
const reason = item.isReceipt === false ? 'non_receipt' : 'extraction_failed';

return [
  {
    json: {
      status: 'skipped',
      reason,
      message:
        reason === 'non_receipt'
          ? 'Email was processed successfully but does not appear to be a receipt.'
          : 'Receipt extraction failed. Check the email text, attachment quality, or OpenAI node output.',
      messageId: item.messageId,
      receiptHash: item.receiptHash,
      extractionStatus: item.extractionStatus,
      extractionFailureReason: item.extractionFailureReason || '',
      extractionSource: item.extractionSource || '',
      originalSubject: item.originalSubject,
      fromEmail: item.fromEmail,
      testScenario: item._testScenario || '',
    },
  },
];

const item = $input.first().json;
const money = `${item.currency || 'USD'} ${Number(item.total || 0).toFixed(2)}`;
const reason =
  item.route === 'review'
    ? 'Needs review'
    : item.route === 'high_value'
      ? 'High-value receipt'
      : item.route === 'warranty'
        ? 'Warranty or return date found'
        : 'Receipt logged';

const details = [
  `Reason: ${reason}`,
  `Merchant: ${item.merchant}`,
  `Total: ${money}`,
  `Category: ${item.category}`,
  `Purchase date: ${item.purchaseDate || 'Not found'}`,
  `Tax deductible: ${item.taxDeductible ? 'yes' : 'no'}`,
  `Tax category: ${item.taxCategory || 'None'}`,
  `Confidence: ${item.confidence}/100`,
  item.warrantyItems ? `Warranty items: ${item.warrantyItems}` : '',
  item.returnDeadline ? `Return deadline: ${item.returnDeadline}` : '',
  item.warrantyEndDate ? `Warranty end: ${item.warrantyEndDate}` : '',
  `Subject: ${item.originalSubject}`,
].filter(Boolean);

const slackMessage = [`*${reason}: ${item.merchant}*`, '', ...details.map((line) => `• ${line}`)].join('\n');
const teamsMessage = [`**${reason}: ${item.merchant}**`, '', ...details.map((line) => `- ${line}`)].join('\n');

return [
  {
    json: {
      ...item,
      useSlackAlert: Boolean(item.shouldAlert && item.useSlack),
      useTeamsAlert: Boolean(item.shouldAlert && item.useTeams),
      slackMessage,
      teamsMessage,
    },
  },
];

const item = $input.first().json;
return [
  {
    json: {
      status: 'ok',
      expenseLog: item.expenseLog,
      sheetsLogged: item.sheetsLogged || 'no',
      airtableLogged: item.airtableLogged || 'no',
      merchant: item.Merchant,
      total: item.Total,
      category: item.Category,
      needsReview: item['Needs Review'],
      highValue: item['High Value'],
      alertSent: item['Alert Sent'],
      testScenario: item._testScenario || '',
    },
  },
];

const item = $input.first().json;
return [
  {
    json: {
      status: 'skipped',
      reason: item.isDuplicate ? 'duplicate_receipt' : 'filtered',
      messageId: item.messageId,
      receiptHash: item.receiptHash,
      testScenario: item._testScenario || '',
    },
  },
];
